            src = tf.create("generic.go", """package generic

    import "errors"

    func Find[T comparable](slice []T, target T) (int, error) {
        for i, v := range slice {
            if v == target {
                return i, nil
            }
        }
        return -1, errors.New("not found")
    }
    """)
